// Impressão gráfica via PDF
app.post('/api/print-ticket', async (req, res) => {
    const { displayId, serviceName, priority, createdAt, fontSize } = req.body;
    const printerConfig = await getConfig('printerConfig') || {};
    const systemInfo = await getConfig('systemInfo') || {};

    if (!printerConfig.printerName) return res.status(400).json({ success: false, message: 'Impressora não configurada.' });

    const scale = parseInt(fontSize || printerConfig.fontSize) || 2;
    const baseSize = 40; 
    const passwordFontSize = baseSize + (scale * 10);
    const date = new Date(createdAt);
    const widthMm = parseInt(String(printerConfig.paperWidth).replace(/\D/g, '')) || 80;

    let rawHtml = printerConfig.ticketTemplate || DEFAULT_TICKET_TEMPLATE;
    const logoImg = systemInfo.clientLogo ? `<img src="${systemInfo.clientLogo}" class="logo" />` : '';

    // Replace Variables
    const map = {
        '{{LOGO}}': logoImg,
        '{{EMPRESA}}': systemInfo.clientName || 'SISFILA',
        '{{SENHA}}': displayId,
        '{{SERVICO}}': serviceName,
        '{{PRIORIDADE}}': priority,
        '{{DATA}}': date.toLocaleDateString('pt-BR'),
        '{{HORA}}': date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
        '{{FONT_SIZE_PX}}': passwordFontSize
    };

    for (const [k, v] of Object.entries(map)) rawHtml = rawHtml.replace(new RegExp(k, 'g'), v);

    // Inject CSS for Page Size
    const css = `<style>@page { margin: 0; size: ${widthMm}mm auto; } body { width: ${widthMm}mm; }</style>`;
    rawHtml = rawHtml.includes('<head>') ? rawHtml.replace('<head>', '<head>' + css) : css + rawHtml;

    try {
        const browser = await puppeteer.launch({ headless: true });
        const page = await browser.newPage();
        await page.setViewport({ width: Math.ceil(widthMm * 3.78), height: 800 });
        await page.setContent(rawHtml, { waitUntil: 'networkidle0' });
        await page.pdf({ path: TEMP_PDF_FILE, width: `${widthMm}mm`, printBackground: true, margin: { top:0, right:0, bottom:0, left:0 } });
        await browser.close();

        const cmd = `"${SUMATRA_EXE}" -print-to "${printerConfig.printerName}" -silent "${TEMP_PDF_FILE}"`;
        exec(cmd, (error) => {
            setTimeout(() => { try { fs.unlinkSync(TEMP_PDF_FILE); } catch(e) {} }, 5000);
            if (error) res.status(500).json({ success: false });
            else res.json({ success: true });
        });
    } catch(err) {
        console.error(err);
        res.status(500).json({ success: false });
    }
});

// Backup & Restore
app.get('/api/backup', async (req, res) => {
    const tickets = await dbAll("SELECT * FROM tickets");
    const services = await dbAll("SELECT * FROM services");
    const users = await dbAll("SELECT * FROM users");
    const config = await dbAll("SELECT * FROM config");

    // Converte config array para objeto
    const configObj = config.reduce((acc, cur) => {
        try { acc[cur.key] = JSON.parse(cur.value); } catch(e){ acc[cur.key] = cur.value; }
        return acc;
    }, {});

    const backup = { tickets, services, users, config: configObj };
    res.setHeader('Content-disposition', 'attachment; filename=sisfila_backup.json');
    res.setHeader('Content-type', 'application/json');
    res.send(JSON.stringify(backup, null, 2));
});

app.post('/api/restore', async (req, res) => {
    const { data } = req.body;
    if (!data) return res.status(400).json({ success: false });

    try {
        await dbRun("BEGIN TRANSACTION");

        // Limpar
        await dbRun("DELETE FROM tickets");
        await dbRun("DELETE FROM services");
        await dbRun("DELETE FROM users");
        await dbRun("DELETE FROM config");

        // Inserir
        if (data.services) for (const s of data.services) await dbRun("INSERT INTO services (id, name, active) VALUES (?,?,?)", [s.id, s.name, s.active]);
        if (data.users) for (const u of data.users) await dbRun("INSERT INTO users (id, name, username, password, deskNumber, serviceId, role, active) VALUES (?,?,?,?,?,?,?,?)", [u.id, u.name, u.username, u.password, u.deskNumber, u.serviceId, u.role, u.active]);
        if (data.tickets) for (const t of data.tickets) await dbRun("INSERT INTO tickets (id, displayId, serviceId, serviceName, priority, status, createdAt, calledAt, startedAt, finishedAt, attendantName, deskNumber) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)", [t.id, t.displayId, t.serviceId, t.serviceName, t.priority, t.status, t.createdAt, t.calledAt, t.startedAt, t.finishedAt, t.attendantName, t.deskNumber]);

        if (data.config) {
            for (const [k, v] of Object.entries(data.config)) {
                await setConfig(k, v);
            }
        }

        await dbRun("COMMIT");
        io.emit('sync-update', { type: 'RESET' });
        res.json({ success: true });
    } catch (e) {
        await dbRun("ROLLBACK");
        console.error(e);
        res.status(500).json({ success: false });
    }
});

