// --- SOCKET.IO COM SQLITE ---

io.on('connection', async (socket) => {
    // Carrega dados iniciais do banco
    try {
        const tickets = await dbAll("SELECT * FROM tickets ORDER BY createdAt ASC");
        const services = await dbAll("SELECT * FROM services WHERE active = 1");
        const users = await dbAll("SELECT * FROM users WHERE active = 1");
        socket.emit('initial-data', { tickets, services, users });
    } catch (e) { console.error("Erro Socket Init", e); }

    socket.on('update-tickets', async (data) => {
        const items = Array.isArray(data) ? data : [data];
        for (const t of items) {
            const exists = await dbGet("SELECT id FROM tickets WHERE id = ?", [t.id]);
            if (exists) {
                await dbRun("UPDATE tickets SET status=?, calledAt=?, startedAt=?, finishedAt=?, attendantName=?, deskNumber=? WHERE id=?", 
                    [t.status, t.calledAt, t.startedAt, t.finishedAt, t.attendantName, t.deskNumber, t.id]);
            } else {
                await dbRun("INSERT INTO tickets (id, displayId, serviceId, serviceName, priority, status, createdAt, calledAt, startedAt, finishedAt, attendantName, deskNumber) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)",
                    [t.id, t.displayId, t.serviceId, t.serviceName, t.priority, t.status, t.createdAt, t.calledAt, t.startedAt, t.finishedAt, t.attendantName, t.deskNumber]);
            }
        }
        socket.broadcast.emit('sync-update', { type: 'TICKETS', data: data });
    });

    socket.on('update-services', async (data) => {
        const items = Array.isArray(data) ? data : [data];
        for (const s of items) {
            const exists = await dbGet("SELECT id FROM services WHERE id = ?", [s.id]);
            if (exists) await dbRun("UPDATE services SET name=? WHERE id=?", [s.name, s.id]);
            else await dbRun("INSERT INTO services (id, name, active) VALUES (?,?,?)", [s.id, s.name, 1]);
        }
        socket.broadcast.emit('sync-update', { type: 'SERVICES', data: data });
    });

    socket.on('delete-service', async (id) => {
        await dbRun("DELETE FROM services WHERE id = ?", [id]);
        socket.broadcast.emit('sync-delete-service', id);
    });

    socket.on('update-users', async (data) => {
        const items = Array.isArray(data) ? data : [data];
        for (const u of items) {
            const exists = await dbGet("SELECT id FROM users WHERE id = ?", [u.id]);
            if (exists) await dbRun("UPDATE users SET name=?, username=?, password=?, deskNumber=?, serviceId=?, role=? WHERE id=?", 
                [u.name, u.username, u.password, u.deskNumber, u.serviceId, u.role, u.id]);
            else await dbRun("INSERT INTO users (id, name, username, password, deskNumber, serviceId, role, active) VALUES (?,?,?,?,?,?,?,?)", 
                [u.id, u.name, u.username, u.password, u.deskNumber, u.serviceId, u.role, 1]);
        }
        socket.broadcast.emit('sync-update', { type: 'USERS', data: data });
    });

    socket.on('delete-user', async (id) => {
        await dbRun("DELETE FROM users WHERE id = ?", [id]);
        socket.broadcast.emit('sync-delete-user', id);
    });
});

