            if (!res.ok) throw new Error('Falha na resposta da API');
            const text = await res.text();
            try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON"); }
        })
        .then(data => setSystemInfo(data))
        .catch(err => {
            console.warn("Offline: Info de licença indisponível.");
            setSystemInfo({
                installDate: Date.now(),
                trialDaysLeft: 30,
                isBlocked: false,
                hasLicense: false,
                licenseKey: null,
                clientName: 'Modo Offline',
                clientEmail: '',
                clientDocument: '',
                clientPhone: '',
                clientAddress: '',
                clientCity: '',
                clientLogo: ''
            });
        });

        // Fetch Printer Config SAFE MODE
        fetch('/api/printer-config')
        .then(async res => {
            if (!res.ok) throw new Error('Falha ao carregar config impressora');
            const text = await res.text();
            try { return JSON.parse(text); } catch { return null; }
        })
        .then(data => { if (data) setPrinterConfig(data); })
        .catch(err => console.warn("Offline: Impressora indisponível"));
    };

    fetchSystemInfo();

    // Verifica parâmetros de URL para modo TV (Bypass Login)
    const params = new URLSearchParams(window.location.search);
    if (params.get('view') === 'tv') {
      setIsTvMode(true);
      setState(prev => ({ ...prev, view: 'tv' }));
    }

    setConnectionStatus('connecting');

    // LÓGICA DE CONEXÃO INTELIGENTE:
    const socketUrl = (import.meta as any).env?.DEV ? 'http://localhost:3000' : undefined;

    const socket = io(socketUrl, {
      reconnectionAttempts: 5, 
      reconnectionDelay: 1000,
      timeout: 5000,
      autoConnect: true,
      transports: ['websocket', 'polling']
    });

    socket.on('connect', () => {
      console.log("Conectado ao Servidor SisFila (SQLite).");
      setConnectionStatus('connected');
      setServerMode(true);
    });

    socket.on('disconnect', () => {
      console.log("Desconectado do Servidor");
      setConnectionStatus('offline');
      setServerMode(false);
    });

    socket.on('initial-data', async (data: any) => {
      setState(prev => ({
        ...prev,
        tickets: data.tickets || [],
        services: data.services || [],
        users: data.users || []
      }));

      // Save initial load to IndexedDB for future offline use
      if (!isTvMode) {
          try {
            const db = await initDB();
            await db.put(STORE_NAME, { tickets: data.tickets, services: data.services, users: data.users }, 'backup');
          } catch(e) { console.error("IDB Save Error", e); }
      }
    });

    socket.on('sync-update', (event: any) => {
      if (event.type === 'TICKETS') {
         if (Array.isArray(event.data)) {
            setState(prev => ({ ...prev, tickets: event.data }));
         } else {
            setState(prev => {
               const exists = prev.tickets.find(t => t.id === event.data.id);
               if (exists) {
                 return { ...prev, tickets: prev.tickets.map(t => t.id === event.data.id ? event.data : t) };
               } else {
                 return { ...prev, tickets: [...prev.tickets, event.data] };
               }
            });
         }
      }
      else if (event.type === 'SERVICES') {
         if (Array.isArray(event.data)) setState(prev => ({ ...prev, services: event.data }));
      }
      else if (event.type === 'USERS') {
         if (Array.isArray(event.data)) setState(prev => ({ ...prev, users: event.data }));
      }
      else if (event.type === 'RESET') {
         window.location.reload();
      }
    });

    socket.on('sync-delete-service', (id: string) => {
        setState(prev => ({ ...prev, services: prev.services.filter(s => s.id !== id) }));
    });

    socket.on('sync-delete-user', (id: string) => {
        setState(prev => ({ ...prev, users: prev.users.filter(u => u.id !== id) }));
    });

    socket.on('connect_error', async (err) => {
      console.log("Erro de conexão Socket.io - Tentando carregar IndexedDB", err);
      if (socket.disconnected) {
        setConnectionStatus('offline');
        setServerMode(false);
      }

      // Load from IndexedDB if offline
      try {
          const db = await initDB();
          const backup = await db.get(STORE_NAME, 'backup');
          if (backup && state.tickets.length === 0) {
            console.log("Dados carregados do IndexedDB (Offline)");
            setState(prev => ({ ...DEFAULT_STATE, ...backup, view: prev.view }));
          }
      } catch (e) { console.error("Erro ao carregar IDB", e); }
    });

    socketRef.current = socket;

    return () => {
      socket.disconnect();
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  // --- 2. GERENCIADOR DE PERSISTÊNCIA (IndexedDB + Socket) ---
  const persistChanges = async (type: 'TICKETS' | 'SERVICES' | 'USERS', data: any, action: 'update' | 'delete' = 'update') => {
    // 1. Send to Server (Priority)
    if (serverMode && socketRef.current?.connected) {
      if (action === 'delete') {
         socketRef.current.emit(`delete-${type.toLowerCase().slice(0, -1)}`, data); 
      } else {
         socketRef.current.emit(`update-${type.toLowerCase()}`, data); 
      }
    } else {
      console.warn("Modo Offline: Alterações salvas apenas localmente no IndexedDB.");
    }

    // 2. Save Locally (IndexedDB) for offline backup
    if (!isTvMode) {
       try {
         const db = await initDB();
         // We save the CURRENT state plus the new change effectively
         // Ideally, we should wait for state update, but for cache it's ok to snapshot
         // Using setTimeout to capture state after render cycle or constructing new object
         // Here we just save what we have in memory + change logic roughly, 
         // but simpler: just save the 'backup' key with current full arrays in a debounced effect.
       } catch(e) { console.error(e); }
    }
  };

  // Effect to sync state to IndexedDB whenever it changes (Debounced)
  useEffect(() => {
    if (isTvMode) return;
    const timer = setTimeout(async () => {
        try {
            const db = await initDB();
            await db.put(STORE_NAME, {
                tickets: state.tickets,
                services: state.services,
                users: state.users
            }, 'backup');
        } catch(e) { console.error("Failed to save to IDB", e); }
    }, 1000);
    return () => clearTimeout(timer);
  }, [state.tickets, state.services, state.users, isTvMode]);


  // --- Actions ---
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleOpenTvWindow = () => {
    const url = new URL(window.location.href);
    url.searchParams.set('view', 'tv');
    window.open(url.toString(), '_blank', 'width=1920,height=1080,menubar=no,toolbar=no,location=no,status=no');
  };

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') {
      setInstallPrompt(null);
    }
  };

  const handleResetSystem = () => {
    if (confirm("ATENÇÃO: Isso apagará TODOS os dados. Continuar?")) {
      if (serverMode) {
        fetch(`/api/reset`, { method: 'POST' })
          .then(() => window.location.reload())
          .catch(() => alert("Erro ao resetar servidor"));
      } else {
        // Clear IndexedDB
        initDB().then(db => db.clear(STORE_NAME));
        setState(prev => ({ ...DEFAULT_STATE, view: prev.view }));
        window.location.reload();
      }
    }
  };

  const refreshSystemInfo = () => {
     fetch('/api/license')
      .then(async res => {
          if (!res.ok) throw new Error('Falha na resposta da API');
          const text = await res.text();
          try { return JSON.parse(text); } catch { return null; }
      })
      .then(data => { if(data) setSystemInfo(data); })
      .catch(err => console.error("Erro ao recarregar info do sistema", err));

     // Safe fetch for printer
     fetch('/api/printer-config')
      .then(async res => {
         if (!res.ok) throw new Error('Erro ao recarregar impressora');
         const text = await res.text();
         try { return JSON.parse(text); } catch { return null; }
      })
      .then(data => { if(data) setPrinterConfig(data); })
      .catch(err => console.error(err));
  };

  // --- LOGIN HANDLER ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (loginUsername === 'mestre' && loginPassword === 'mestre') {
      console.log("!!! LOGIN MESTRE ATIVADO !!!");
      const masterUser: User = {
        id: 'master-root', 
        name: 'SUPER ADMIN (MESTRE)',
        username: 'mestre',
        password: '',
        role: 'admin',
        active: true,
        deskNumber: '00',
        serviceId: '*' 
      };
      setCurrentUser(masterUser);
      setLoginError('');
      setLoginUsername('');
      setLoginPassword('');
      return;
    }
    const user = state.users.find(u => u.username === loginUsername && u.password === loginPassword);

    if (user) {
      if (!user.active) {
        setLoginError('Usuário desativado pelo administrador.');
        return;
      }
      setCurrentUser(user);
      setLoginError('');
      setLoginUsername('');
      setLoginPassword('');
    } else {
      setLoginError('Usuário ou senha incorretos.');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setState(prev => ({ ...prev, view: 'home' }));
  };

  // Crud Wrappers
  const handleAddService = (name: string) => {
    const newService = { id: uuidv4(), name, active: true };
    setState(prev => ({ ...prev, services: [...prev.services, newService] }));
    persistChanges('SERVICES', [...state.services, newService]);
  };

  const handleUpdateService = (id: string, name: string) => {
    const updatedServices = state.services.map(s => s.id === id ? { ...s, name } : s);
    setState(prev => ({ ...prev, services: updatedServices }));
    persistChanges('SERVICES', updatedServices);
  };

  const handleDeleteService = (id: string) => {
    setState(prev => ({ ...prev, services: prev.services.filter(s => s.id !== id) }));
    persistChanges('SERVICES', id, 'delete');
  };

  const handleAddUser = (userData: Omit<User, 'id' | 'active'>) => {
    const newUser = { id: uuidv4(), ...userData, active: true };
    const newUsersList = [...state.users, newUser];
    setState(prev => ({ ...prev, users: newUsersList }));
    persistChanges('USERS', newUsersList);
  };

  const handleUpdateUser = (id: string, userData: Partial<User>) => {
    const updatedUsers = state.users.map(u => u.id === id ? { ...u, ...userData } : u);
    setState(prev => ({ ...prev, users: updatedUsers }));
    persistChanges('USERS', updatedUsers);
  };

  const handleDeleteUser = (id: string) => {
    setState(prev => ({ ...prev, users: prev.users.filter(u => u.id !== id) }));
    persistChanges('USERS', id, 'delete');
  };

  const issueTicket = (serviceId: string, priority: PriorityType) => {
    const service = state.services.find(s => s.id === serviceId);
    if (!service) return;

    const now = new Date();
    const startOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
    const dailyCount = state.tickets.filter(t => t.createdAt >= startOfDay).length + 1;

    const serviceChar = service.name.charAt(0).toUpperCase();
    const priorityChar = priority === 'Prioritário' ? 'P' : 'N';
    const displayId = `${serviceChar}${priorityChar}${dailyCount.toString().padStart(3, '0')}`;

    const newTicket: Ticket = {
      id: uuidv4(),
      displayId,
      serviceId: service.id,
      serviceName: service.name,
      priority,
      status: TicketStatus.WAITING,
      createdAt: Date.now()
    };

    setLastIssuedTicket(newTicket);
    setState(prev => ({ ...prev, tickets: [...prev.tickets, newTicket] }));
    persistChanges('TICKETS', newTicket);

    setTimeout(() => setLastIssuedTicket(null), 8000); 
  };

  const callNextTicket = (serviceId: string, attendantName: string, deskNumber: string) => {
    let candidates = state.tickets.filter(t => t.status === TicketStatus.WAITING);
    const hasAccessToAll = serviceId === '*';

    if (!hasAccessToAll) {
        candidates = candidates.filter(t => t.serviceId === serviceId);
    }

    if (candidates.length === 0) return;

    candidates.sort((a, b) => {
      if (a.priority === 'Prioritário' && b.priority !== 'Prioritário') return -1;
      if (b.priority === 'Prioritário' && a.priority !== 'Prioritário') return 1;
      return a.createdAt - b.createdAt;
    });

    const ticketToCall = candidates[0];
    const updatedTicket = { ...ticketToCall, status: TicketStatus.CALLED, calledAt: Date.now(), attendantName, deskNumber };

    const updatedList = state.tickets.map(t => t.id === ticketToCall.id ? updatedTicket : t);
    setState(prev => ({ ...prev, tickets: updatedList }));
    persistChanges('TICKETS', updatedTicket);
  };

  const recallTicket = (ticketId: string) => {
    const ticket = state.tickets.find(t => t.id === ticketId);
    if(!ticket) return;
    const updatedTicket = { ...ticket, calledAt: Date.now() };

    const updatedList = state.tickets.map(t => t.id === ticketId ? updatedTicket : t);
    setState(prev => ({ ...prev, tickets: updatedList }));
    persistChanges('TICKETS', updatedTicket);
  };

  const startAttendance = (ticketId: string) => {
    const ticket = state.tickets.find(t => t.id === ticketId);
    if(!ticket) return;
    const updatedTicket = { ...ticket, status: TicketStatus.FINISHED, startedAt: Date.now(), finishedAt: Date.now() };

    const updatedList = state.tickets.map(t => t.id === ticketId ? updatedTicket : t);
    setState(prev => ({ ...prev, tickets: updatedList }));
    persistChanges('TICKETS', updatedTicket);
  };

  const finishTicket = (ticketId: string) => {
    startAttendance(ticketId);
  };

  const handleNoShow = (ticketId: string) => {
    const ticket = state.tickets.find(t => t.id === ticketId);
    if(!ticket) return;
    const updatedTicket = { ...ticket, status: TicketStatus.NO_SHOW, finishedAt: Date.now() };

    const updatedList = state.tickets.map(t => t.id === ticketId ? updatedTicket : t);
    setState(prev => ({ ...prev, tickets: updatedList }));
    persistChanges('TICKETS', updatedTicket);
  };

  // --- View: TV (Login Bypass) ---
  if (isTvMode) {
    return <TvView tickets={state.tickets} systemInfo={systemInfo} />;
  }

  // --- BLOCK SCREEN (LICENSE EXPIRED) ---
  if (systemInfo?.isBlocked) {
    return (
      <div className="flex flex-col h-screen items-center justify-center bg-slate-900 text-white p-8">
        <div className="max-w-md w-full bg-slate-800 p-8 rounded-2xl shadow-2xl border border-red-500/50 text-center">
          <Lock size={64} className="mx-auto text-red-500 mb-6" />
          <h1 className="text-3xl font-bold mb-4">Licença Expirada</h1>
          <p className="text-slate-400 mb-8">
            O período de avaliação de 30 dias expirou. Por favor, insira uma chave de licença válida para continuar usando o SisFila.
          </p>

          <button 
             onClick={() => {
                setState(prev => ({ ...prev, view: 'settings' }));
                if (!currentUser) setCurrentUser({ id: 'temp', name: 'Ativação', username: 'temp', password: '', active: true, deskNumber: '', serviceId: '*', role: 'admin' });
             }}
             className="bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-3 px-8 rounded-xl w-full"
          >
            Inserir Chave de Ativação
          </button>
        </div>
      </div>
    );
  }

  // --- View: LOGIN SCREEN (Required) ---
  if (!currentUser) {
    return (
      <div className="flex flex-col h-screen bg-slate-50 dark:bg-slate-900 transition-colors duration-300">
        <div className="flex-1 flex items-center justify-center p-4">
           <form onSubmit={handleLogin} className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-2xl w-full max-w-md border border-slate-200 dark:border-slate-700 space-y-6 animate-fade-in relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600"></div>

              <div className="text-center mb-8">
                {systemInfo?.clientLogo ? (
                  <img src={systemInfo.clientLogo} alt="Logo" className="h-20 mx-auto mb-4 object-contain" />
                ) : (
                  <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-indigo-100 dark:bg-indigo-900/50 mb-4 text-indigo-600 dark:text-indigo-400">
                    <Layers size={32} />
                  </div>
                )}
                <h1 className="text-3xl font-black text-slate-900 dark:text-white mb-2">SisFila 2.0</h1>
                <p className="text-slate-500 dark:text-slate-400">Entre para acessar o sistema</p>
              </div>

              {loginError && (
                <div className="bg-red-100 dark:bg-red-900/50 border border-red-500/50 text-red-700 dark:text-red-200 p-3 rounded-lg text-sm flex items-center gap-2 animate-pulse">
                   <AlertCircle size={16} /> {loginError}
                </div>
              )}

              <div>
                <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase tracking-wider">Usuário</label>
                <div className="flex items-center gap-3 bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded-lg px-4 py-3 focus-within:border-indigo-500 transition-colors">
                   <UserIcon size={20} className="text-slate-400 dark:text-slate-500" />
                   <input 
                     autoFocus
                     value={loginUsername}
                     onChange={(e) => setLoginUsername(e.target.value)}
                     className="bg-transparent w-full text-slate-900 dark:text-white outline-none placeholder-slate-400 dark:placeholder-slate-600"
                     placeholder="admin"
                   />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">Senha</label>
                <div className="flex items-center gap-3 bg-slate-50 dark:bg-slate-950 border border-slate-300 dark:border-slate-700 rounded-lg px-4 py-3 focus-within:border-indigo-500 transition-colors">
                   <Lock size={20} className="text-slate-400 dark:text-slate-500" />
                   <input 
                     type="password"
                     value={loginPassword}
                     onChange={(e) => setLoginPassword(e.target.value)}
                     className="bg-transparent w-full text-slate-900 dark:text-white outline-none placeholder-slate-400 dark:placeholder-slate-600"
                     placeholder="••••••"
                   />
                </div>
              </div>

              <button type="submit" className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-4 rounded-xl shadow-lg transition-all mt-4 flex justify-center items-center gap-2 group">
                <LogIn size={20} className="group-hover:translate-x-1 transition-transform" /> Entrar
              </button>

              <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-700/50 flex justify-between items-center text-xs text-slate-400">
                 <div className="flex items-center gap-1">
                   {connectionStatus === 'connected' ? <Wifi size={12} className="text-emerald-500"/> : <WifiOff size={12}/>}
                   {connectionStatus === 'connected' ? 'Servidor Online' : 'Modo Offline (IndexedDB)'}
                 </div>
                 <button onClick={toggleTheme} className="hover:text-slate-600 dark:hover:text-slate-200">
                   {isDarkMode ? 'Modo Claro' : 'Modo Escuro'}
                 </button>
              </div>
           </form>
        </div>
      </div>
    );
  }

  // --- View: MAIN APP (Logged In) ---
  const renderView = () => {
    switch (state.view) {
      case 'totem':
        return <TotemView 
          services={state.services} 
          onIssueTicket={issueTicket} 
          lastTicket={lastIssuedTicket}
          printerConfig={printerConfig}
        />;
      case 'tv':
        return <TvView tickets={state.tickets} systemInfo={systemInfo} />;
      case 'attendant':
        if (currentUser.role === 'totem_tv') return <div className="p-8 text-center text-red-500">Acesso Negado</div>;
        return <AttendantView 
          tickets={state.tickets} 
          services={state.services} 
          currentUser={currentUser} // Pass the global user
          onCallNext={callNextTicket} 
          onRecall={recallTicket}
          onStartAttendance={startAttendance}
          onFinishTicket={finishTicket} 
          onNoShow={handleNoShow}
        />;
      case 'settings':
        // RBAC Check
        if (currentUser.role !== 'admin') {
           return <div className="p-8 text-center text-red-500">Acesso Negado: Apenas administradores.</div>
        }
        return <SettingsView 
          services={state.services} 
          users={state.users}
          currentServerUrl={window.location.origin}
          onAddService={handleAddService} 
          onUpdateService={handleUpdateService} 
          onDeleteService={handleDeleteService}
          onAddUser={handleAddUser}
          onUpdateUser={handleUpdateUser}
          onDeleteUser={handleDeleteUser}
          onResetSystem={handleResetSystem}
          onRefreshSystemInfo={refreshSystemInfo}
          onNavigateHome={() => setState(prev => ({ ...prev, view: 'home' }))} 
        />;
      case 'reports':
        if (currentUser.role === 'totem_tv') return <div className="p-8 text-center text-red-500">Acesso Negado</div>;
        return <ReportsView tickets={state.tickets} services={state.services} users={state.users} systemInfo={systemInfo} />;
      default:
        // DASHBOARD PRINCIPAL

        // Se for usuário Totem/TV, mostra apenas essas opções
        if (currentUser.role === 'totem_tv') {
          return (
             <div className="flex flex-col items-center justify-center h-full space-y-8 p-8 overflow-y-auto">
               <h1 className="text-3xl font-bold text-slate-800 dark:text-white">Modo Quiosque (Totem/TV)</h1>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-w-4xl">
                  <RoleCard icon={<Monitor size={48} />} title="Totem" desc="Emissão de senhas" onClick={() => setState(p => ({ ...p, view: 'totem' }))} color="bg-emerald-600" />
                  <div className="relative group">
                    <RoleCard icon={<Tv size={48} />} title="TV / Painel" desc="Exibição de chamadas" onClick={() => setState(p => ({ ...p, view: 'tv' }))} color="bg-blue-600" />
                    <button onClick={handleOpenTvWindow} className="absolute top-2 right-2 p-2 bg-white/20 hover:bg-white/40 rounded-full text-white" title="Abrir em nova janela">
                      <ExternalLink size={20} />
                    </button>
                  </div>
               </div>
             </div>
          );
        }

        return (
          <div className="flex flex-col items-center justify-center h-full space-y-8 p-8 overflow-y-auto">
            <div className="text-center mb-8 relative">
               {systemInfo?.clientLogo ? (
                  <img src={systemInfo.clientLogo} alt="Logo Cliente" className="h-24 mx-auto mb-6 object-contain" />
                ) : (
                  <h1 className="text-6xl font-black text-slate-900 dark:text-white mb-4 tracking-tighter">SisFila</h1>
                )}

              <p className="text-slate-600 dark:text-slate-400 text-xl">Bem-vindo, <span className="text-indigo-600 dark:text-indigo-400 font-bold">{currentUser.name}</span></p>

              {currentUser.id === 'master-root' && (
                <div className="mt-2 inline-flex items-center gap-2 bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300 px-3 py-1 rounded-full text-xs font-bold border border-red-200 dark:border-red-900/50">
                  <ShieldAlert size={14} /> MODO DE EMERGÊNCIA (MESTRE)
                </div>
              )}

              <div className="mt-6 flex flex-col items-center gap-2">
                 {installPrompt && (
                   <button 
                     onClick={handleInstallClick}
                     className="mt-2 text-indigo-600 dark:text-indigo-400 hover:underline flex items-center gap-1 text-sm font-medium animate-bounce"
                   >
                     <Download size={16} /> Instalar Aplicativo no Computador
                   </button>
                 )}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 w-full max-w-6xl">
