const LayoutTab = () => {
  const [template, setTemplate] = useState('');
  const [msg, setMsg] = useState('');

  const DEFAULT_TEMPLATE = `<html>
  <head>
    <style>
      @page { margin: 0; }
      body { 
        margin: 0; 
        padding: 5px; 
        font-family: 'Arial', sans-serif; 
        text-align: center;
        color: black;
      }
      .logo { max-width: 80%; max-height: 60px; margin-bottom: 5px; }
      h2 { font-size: 14px; margin: 2px 0; text-transform: uppercase; }
      .divider { border-top: 1px dashed black; margin: 5px 0; width: 100%; }
      .label { font-size: 12px; font-weight: bold; margin-top: 5px; }
      .password { 
        font-size: {{FONT_SIZE_PX}}px; 
        font-weight: 900; 
        margin: 5px 0; 
        line-height: 1;
      }
      .info { font-size: 16px; font-weight: bold; margin: 2px 0; }
      .meta { font-size: 10px; margin-top: 10px; }
    </style>
  </head>
  <body>
    {{LOGO}}
    <h2>{{EMPRESA}}</h2>
    <div class="divider"></div>
    <div class="label">SENHA</div>
    <div class="password">{{SENHA}}</div>
    <div class="info">{{SERVICO}}</div>
    <div class="info">{{PRIORIDADE}}</div>
    <div class="divider"></div>
    <div class="meta">{{DATA}} - {{HORA}}</div>
    <br/><br/>
  </body>
</html>`;

  useEffect(() => {
    fetch('/api/printer-config')
      .then(async res => {
         const text = await res.text();
         try { return JSON.parse(text); } catch { return {}; }
      })
      .then(data => {
        if(data.ticketTemplate) setTemplate(data.ticketTemplate);
        else setTemplate(DEFAULT_TEMPLATE);
      });
  }, []);

  const handleSave = async () => {
    try {
       // Need to fetch current config first to not overwrite other settings
       const currentRes = await fetch('/api/printer-config');
       const currentConfig = await currentRes.json();

       await fetch('/api/printer-config', {
         method: 'POST',
         headers: { 'Content-Type': 'application/json' },
         body: JSON.stringify({ ...currentConfig, ticketTemplate: template })
       });
       setMsg('Layout salvo!');
       setTimeout(() => setMsg(''), 2000);
    } catch(e) {
       setMsg('Erro ao salvar');
    }
  };

  const handleReset = () => {
    if(confirm("Deseja restaurar o layout padrão?")) {
      setTemplate(DEFAULT_TEMPLATE);
    }
  };

  return (
    <div className="animate-fade-in">
      <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-4 flex items-center gap-2">
         <LayoutTemplate size={24} className="text-indigo-600 dark:text-indigo-400" /> Editor de Layout da Senha
      </h3>

      <p className="text-sm text-slate-500 mb-4">
        Edite o HTML e CSS abaixo para personalizar o cupom impresso. Use as variáveis para inserir dados dinâmicos.
      </p>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[500px]">
         <div className="lg:col-span-2 flex flex-col h-full">
            <textarea 
              value={template}
              onChange={e => setTemplate(e.target.value)}
              className="flex-1 w-full bg-slate-900 text-emerald-400 font-mono text-xs p-4 rounded-lg border border-slate-700 outline-none resize-none"
              spellCheck={false}
            />
            <div className="flex gap-2 mt-4">
               <button onClick={handleSave} className="bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-2 px-6 rounded-lg shadow"><Save size={18} className="inline mr-2"/> Salvar Layout</button>
               <button onClick={handleReset} className="bg-slate-200 hover:bg-slate-300 text-slate-800 font-bold py-2 px-6 rounded-lg"><RefreshCw size={18} className="inline mr-2"/> Restaurar Padrão</button>
               {msg && <span className="text-emerald-500 font-bold py-2">{msg}</span>}
            </div>
         </div>

