  const [newName, setNewName] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');

  const handleSaveNew = () => { if (newName.trim()) { onAdd(newName.trim()); setNewName(''); setIsAdding(false); } };
  const handleSaveEdit = () => { if (editingId && editName.trim()) { onEdit(editingId, editName.trim()); setEditingId(null); } };

  return (
    <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden shadow-lg animate-fade-in transition-colors">
      <div className="p-4 bg-slate-50 dark:bg-slate-900/50 flex justify-between items-center border-b border-slate-200 dark:border-slate-700">
        <h3 className="font-bold flex items-center gap-2 text-slate-700 dark:text-white"><Settings size={18} /> Lista de Serviços</h3>
        <button onClick={() => setIsAdding(true)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-3 py-1.5 rounded text-sm flex items-center gap-2"><Plus size={16} /> Adicionar</button>
      </div>
      {isAdding && (
        <div className="p-4 bg-slate-50 dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 flex gap-4 items-center">
          <input autoFocus value={newName} onChange={(e) => setNewName(e.target.value)} placeholder="Nome" className="flex-1 bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-4 py-2 outline-none text-slate-900 dark:text-white" />
          <button onClick={handleSaveNew} className="text-emerald-500 p-2"><Save size={20} /></button>
          <button onClick={() => setIsAdding(false)} className="text-red-500 p-2"><X size={20} /></button>
        </div>
      )}
