                <div className="flex-1 flex gap-4 items-center">
                  <input autoFocus value={editName} onChange={(e) => setEditName(e.target.value)} className="flex-1 bg-white dark:bg-slate-900 border border-indigo-500 rounded px-3 py-1 outline-none text-slate-900 dark:text-white" />
                  <button onClick={handleSaveEdit} className="text-emerald-500 p-2"><Save size={18} /></button>
                  <button onClick={() => setEditingId(null)} className="text-red-500 p-2"><X size={18} /></button>
                </div>
              ) : (
                <>
                  <div className="flex items-center gap-4">
                    <span className="font-medium text-slate-700 dark:text-slate-200">{service.name}</span>
                  </div>
                  <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => { setEditingId(service.id); setEditName(service.name); }} className="p-2 text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 rounded-lg"><Edit2 size={18} /></button>
                    <button onClick={() => onDelete(service.id)} className="p-2 text-slate-400 hover:text-red-600 dark:hover:text-red-400 rounded-lg"><Trash2 size={18} /></button>
                  </div>
                </>
              )}
            </div>
        ))}
      </div>
    </div>
  );
};

const UsersTab = ({ users, services, onAdd, onUpdate, onDelete }: any) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({ name: '', username: '', password: '', deskNumber: '', serviceId: '', role: 'attendant' as UserRole });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => { setFormData(prev => ({ ...prev, [e.target.name]: e.target.value })); };
  const handleStartAdd = () => { setFormData({ name: '', username: '', password: '', deskNumber: '', serviceId: '', role: 'attendant' }); setEditingId(null); setIsAdding(true); };
  const handleStartEdit = (user: User) => {
    setFormData({ name: user.name, username: user.username, password: user.password, deskNumber: user.deskNumber, serviceId: Array.isArray(user.serviceId) ? user.serviceId[0] : user.serviceId, role: user.role || 'attendant' });
    setEditingId(user.id); setIsAdding(true);
  };
  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const payload = { ...formData, deskNumber: formData.deskNumber || '01' };
    if (editingId) onUpdate(editingId, payload); else onAdd(payload);
    setIsAdding(false);
  };

  return (
    <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden shadow-lg animate-fade-in transition-colors">
       <div className="p-4 bg-slate-50 dark:bg-slate-900/50 flex justify-between items-center border-b border-slate-200 dark:border-slate-700">
        <h3 className="font-bold flex items-center gap-2 text-slate-700 dark:text-white"><UserIcon size={18} /> Usuários</h3>
        <button onClick={handleStartAdd} className="bg-indigo-600 hover:bg-indigo-500 text-white px-3 py-1.5 rounded text-sm flex items-center gap-2"><Plus size={16} /> Novo</button>
      </div>
      {isAdding && (
        <form onSubmit={handleSave} className="p-6 bg-white dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 grid grid-cols-1 md:grid-cols-2 gap-4">
           <div className="col-span-2 md:col-span-1">
             <label className="block text-xs text-slate-500 dark:text-slate-400 mb-1">Nome</label>
             <input required name="name" value={formData.name} onChange={handleChange} className="bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-3 py-2 w-full text-slate-900 dark:text-white" />
           </div>
           <div className="col-span-2 md:col-span-1">
             <label className="block text-xs text-slate-500 dark:text-slate-400 mb-1">Função</label>
             <select name="role" value={formData.role} onChange={handleChange} className="bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-3 py-2 w-full text-slate-900 dark:text-white">
                <option value="attendant">Atendente</option><option value="admin">Admin</option><option value="totem_tv">Totem/TV</option>
             </select>
           </div>
           <div className="col-span-2 md:col-span-1">
             <label className="block text-xs text-slate-500 dark:text-slate-400 mb-1">Serviço</label>
             <select name="serviceId" value={formData.serviceId} onChange={handleChange} className="bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-3 py-2 w-full text-slate-900 dark:text-white">
                <option value="">Selecione...</option>
                {formData.role === 'admin' && <option value="*">Todos</option>}
                {services.map((s: Service) => <option key={s.id} value={s.id}>{s.name}</option>)}
             </select>
           </div>
           <div className="col-span-2 md:col-span-1">
             <label className="block text-xs text-slate-500 dark:text-slate-400 mb-1">Login</label>
             <input required name="username" value={formData.username} onChange={handleChange} className="bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-3 py-2 w-full text-slate-900 dark:text-white" />
           </div>
           <div className="col-span-2 md:col-span-1">
             <label className="block text-xs text-slate-500 dark:text-slate-400 mb-1">Senha</label>
             <input required name="password" value={formData.password} onChange={handleChange} className="bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-3 py-2 w-full text-slate-900 dark:text-white" />
           </div>
           <div className="col-span-2 md:col-span-1">
             <label className="block text-xs text-slate-500 dark:text-slate-400 mb-1">Mesa</label>
             <input required name="deskNumber" value={formData.deskNumber} onChange={handleChange} className="bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-3 py-2 w-full text-slate-900 dark:text-white" />
           </div>
           <div className="col-span-2 flex justify-end gap-2 mt-2">
             <button type="button" onClick={() => setIsAdding(false)} className="px-4 py-2 text-slate-500">Cancelar</button>
             <button type="submit" className="px-6 py-2 bg-emerald-600 text-white rounded font-bold">Salvar</button>
           </div>
        </form>
      )}
      <div className="divide-y divide-slate-200 dark:divide-slate-700">
        {users.map((user: User) => {
             const userServices = Array.isArray(user.serviceId) ? user.serviceId : [user.serviceId];
             const isAllServices = userServices.includes('*');
             const serviceNames = userServices.map(sid => {
                 const s = services.find((srv: Service) => srv.id === sid);
                 return s ? s.name : (sid === '*' ? 'Todos' : null);
             }).filter(Boolean).join(', ');
             return (
              <div key={user.id} className="p-4 flex items-center justify-between hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors group">
                <div className="flex items-center gap-4">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center text-white font-bold text-xs bg-indigo-500`}>{user.name.charAt(0)}</div>
                  <div><div className="font-bold text-slate-800 dark:text-white">{user.name}</div><div className="text-xs text-slate-500">{serviceNames || 'Nenhum'}</div></div>
                </div>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => handleStartEdit(user)} className="p-2 text-slate-400 hover:text-indigo-600 rounded-lg"><Edit2 size={18} /></button>
                  <button onClick={() => onDelete(user.id)} className="p-2 text-slate-400 hover:text-red-600 rounded-lg"><Trash2 size={18} /></button>
                </div>
              </div>
             )
        })}
      </div>
    </div>
  );
};

