           <button 
             onClick={() => setSubTab('general')}
             className={`px-3 py-2 text-left rounded-lg text-sm font-bold flex items-center gap-2 ${subTab === 'general' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700'}`}
