const LicenseTab = () => {
  const [key, setKey] = useState('');
  const [status, setStatus] = useState<any>(null);
  const [message, setMessage] = useState('');

  React.useEffect(() => {
    fetch('/api/license')
      .then(async res => {
         if (!res.ok) return {};
         const text = await res.text();
         try { return JSON.parse(text); } catch { return {}; }
      })
      .then(data => setStatus(data))
      .catch(console.error);
  }, []);

  const handleActivate = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await fetch('/api/license', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ key }) });
      const data = await res.json();
      if (data.success) {
        setMessage('Sistema ativado!');
        setStatus((prev: any) => ({ ...prev, hasLicense: true, licenseKey: key, trialDaysLeft: 9999 }));
      } else { setMessage('Erro: ' + data.message); }
    } catch (error) { setMessage('Erro de conexão.'); }
  };

  return (
    <div className="animate-fade-in">
      <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-4 flex items-center gap-2"><Lock size={24} /> Licenciamento</h3>
      {status && (
          <div className="mb-8 p-4 bg-slate-50 dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-700">
             <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-xs text-slate-500 uppercase font-bold">Status</p>
                  <p className={`text-lg font-bold ${status.hasLicense ? 'text-emerald-600' : 'text-yellow-600'}`}>{status.hasLicense ? 'Ativado' : 'Versão Trial'}</p>
                </div>
                {!status.hasLicense && <div><p className="text-xs text-slate-500 uppercase font-bold">Dias</p><p className="text-lg font-bold">{status.trialDaysLeft} dias</p></div>}
             </div>
          </div>
      )}
      <form onSubmit={handleActivate} className="flex gap-2">
         <input required value={key} onChange={e => setKey(e.target.value)} placeholder="Chave de Ativação" className="flex-1 bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded p-3 outline-none text-slate-900 dark:text-white font-mono uppercase" />
         <button type="submit" className="bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 px-6 rounded-lg shadow-lg">Ativar</button>
      </form>
      {message && <p className="mt-2 text-sm">{message}</p>}
    </div>
  );
};

