const { app, BrowserWindow, screen } = require('electron');
const path = require('path');
const { fork } = require('child_process');
const fs = require('fs');

// Previne múltiplas instâncias
const gotTheLock = app.requestSingleInstanceLock();

if (!gotTheLock) {
  app.quit();
} else {
  let mainWindow;
  let serverProcess;

  const createWindow = () => {
    const { width, height } = screen.getPrimaryDisplay().workAreaSize;

    mainWindow = new BrowserWindow({
      width: width,
      height: height,
      icon: path.join(__dirname, '../dist/icon.svg'), // Tenta pegar do build
      webPreferences: {
        nodeIntegration: false,
        contextIsolation: true,
      },
      autoHideMenuBar: true, // Oculta a barra de menu padrão
    });

    // Em produção, o servidor roda na porta 3000 (definido no server.js)
    // O Electron carrega a URL do servidor local
    mainWindow.loadURL('http://localhost:3000');

    // Abre maximizado
    mainWindow.maximize();

    mainWindow.on('closed', () => {
      mainWindow = null;
    });
  };

  const startServer = () => {
    const serverPath = path.join(__dirname, '../server.js');
    const userDataPath = app.getPath('userData'); // Caminho seguro para escrita (AppData)

    if (fs.existsSync(serverPath)) {
      console.log('Iniciando Servidor SisFila:', serverPath);
      // Inicia o server.js como um processo filho independente
      serverProcess = fork(serverPath, [], {
        env: { 
          ...process.env, 
          ELECTRON_RUN: 'true',
          USER_DATA_PATH: userDataPath // Passa o caminho para o server
        }
      });

      serverProcess.on('error', (err) => {
        console.error('Falha ao iniciar servidor:', err);
      });
    } else {
      console.error('ARQUIVO SERVER.JS NÃO ENCONTRADO EM:', serverPath);
    }
  };

  app.on('second-instance', (event, commandLine, workingDirectory) => {
    // Se alguém tentar abrir uma segunda instância, foca na janela principal
    if (mainWindow) {
      if (mainWindow.isMinimized()) mainWindow.restore();
      mainWindow.focus();
    }
  });

  app.whenReady().then(() => {
    startServer();
    // Dá um pequeno tempo para o servidor subir antes de abrir a janela
    setTimeout(createWindow, 2000);

    app.on('activate', () => {
      if (BrowserWindow.getAllWindows().length === 0) createWindow();
    });
  });

  app.on('window-all-closed', () => {
    if (process.platform !== 'darwin') app.quit();
  });

  app.on('before-quit', () => {
    if (serverProcess) {
      serverProcess.kill(); // Mata o processo do servidor Node ao fechar o app
    }
  });
}

