app.post('/api/restore', async (req, res) => {
    const { data } = req.body;
    if (!data) return res.status(400).json({ success: false });

    try {
        await dbRun("BEGIN TRANSACTION");

        // Limpar
        await dbRun("DELETE FROM tickets");
        await dbRun("DELETE FROM services");
        await dbRun("DELETE FROM users");
        await dbRun("DELETE FROM config");

        // Inserir
        if (data.services) for (const s of data.services) await dbRun("INSERT INTO services (id, name, active) VALUES (?,?,?)", [s.id, s.name, s.active]);
        if (data.users) for (const u of data.users) await dbRun("INSERT INTO users (id, name, username, password, deskNumber, serviceId, role, active) VALUES (?,?,?,?,?,?,?,?)", [u.id, u.name, u.username, u.password, u.deskNumber, u.serviceId, u.role, u.active]);
        if (data.tickets) for (const t of data.tickets) await dbRun("INSERT INTO tickets (id, displayId, serviceId, serviceName, priority, status, createdAt, calledAt, startedAt, finishedAt, attendantName, deskNumber) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)", [t.id, t.displayId, t.serviceId, t.serviceName, t.priority, t.status, t.createdAt, t.calledAt, t.startedAt, t.finishedAt, t.attendantName, t.deskNumber]);

        if (data.config) {
            for (const [k, v] of Object.entries(data.config)) {
                await setConfig(k, v);
            }
        }

        await dbRun("COMMIT");
        io.emit('sync-update', { type: 'RESET' });
        res.json({ success: true });
    } catch (e) {
        await dbRun("ROLLBACK");
        console.error(e);
        res.status(500).json({ success: false });
