// Inicialização das Tabelas
function initDB() {
    try {
        db.exec(`
            CREATE TABLE IF NOT EXISTS users (
                id TEXT PRIMARY KEY,
                name TEXT,
                username TEXT,
                password TEXT,
                deskNumber TEXT,
                serviceId TEXT,
                role TEXT,
                active INTEGER DEFAULT 1
            );
            CREATE TABLE IF NOT EXISTS services (
                id TEXT PRIMARY KEY,
                name TEXT,
                active INTEGER DEFAULT 1
            );
            CREATE TABLE IF NOT EXISTS tickets (
                id TEXT PRIMARY KEY,
                displayId TEXT,
                serviceId TEXT,
                serviceName TEXT,
                priority TEXT,
                status TEXT,
                createdAt INTEGER,
                calledAt INTEGER,
                startedAt INTEGER,
                finishedAt INTEGER,
                attendantName TEXT,
                deskNumber TEXT
            );
            CREATE TABLE IF NOT EXISTS config (
                key TEXT PRIMARY KEY,
                value TEXT
            );
        `);

        console.log("Tabelas verificadas/criadas com sucesso.");

        // Verifica e popula dados iniciais se vazio
        const row = db.prepare("SELECT count(*) as count FROM users").get();
        if (row.count === 0) {
            console.log("Populando dados padrão...");
            const insertService = db.prepare("INSERT INTO services (id, name, active) VALUES (?, ?, ?)");
            insertService.run('1', 'Comercial', 1);
            insertService.run('2', 'Financeiro', 1);
            insertService.run('3', 'Suporte', 1);

            const insertUser = db.prepare("INSERT INTO users (id, name, username, password, deskNumber, serviceId, role, active) VALUES (?, ?, ?, ?, ?, ?, ?, ?)");
            insertUser.run('u1', 'Admin', 'admin', 'admin', '01', '1', 'admin', 1);

            // Configurações Padrão
            setConfig('printerConfig', {
                printerName: '', paperWidth: '80', autoPrint: true, fontSize: '2', ticketTemplate: DEFAULT_TICKET_TEMPLATE
            });
            setConfig('systemInfo', {
                installDate: Date.now(), licenseKey: null, clientName: '', clientLogo: ''
            });
        }

    } catch (err) {
        console.error("Erro na inicialização do DB:", err);
    }
}

// Helpers de Configuração (Síncronos agora!)
function getConfig(key) {
    const row = db.prepare("SELECT value FROM config WHERE key = ?").get(key);
    return row ? JSON.parse(row.value) : null;
}

function setConfig(key, value) {
    const json = JSON.stringify(value);
    db.prepare("INSERT INTO config (key, value) VALUES (?, ?) ON CONFLICT(key) DO UPDATE SET value = ?").run(key, json, json);
}

