// --- SOCKET.IO ---

io.on('connection', (socket) => {
    // Carrega dados iniciais do banco
    try {
        const tickets = db.prepare("SELECT * FROM tickets ORDER BY createdAt ASC").all();
        const services = db.prepare("SELECT * FROM services WHERE active = 1").all();
        const users = db.prepare("SELECT * FROM users WHERE active = 1").all();
        socket.emit('initial-data', { tickets, services, users });
    } catch (e) { console.error("Erro Socket Init", e); }

    const updateTicketStmt = db.prepare("UPDATE tickets SET status=?, calledAt=?, startedAt=?, finishedAt=?, attendantName=?, deskNumber=? WHERE id=?");
    const insertTicketStmt = db.prepare("INSERT INTO tickets (id, displayId, serviceId, serviceName, priority, status, createdAt, calledAt, startedAt, finishedAt, attendantName, deskNumber) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)");
    const checkTicketStmt = db.prepare("SELECT id FROM tickets WHERE id = ?");

    socket.on('update-tickets', (data) => {
        const items = Array.isArray(data) ? data : [data];
        db.transaction(() => {
            for (const t of items) {
                const exists = checkTicketStmt.get(t.id);
                if (exists) {
                    updateTicketStmt.run(t.status, t.calledAt, t.startedAt, t.finishedAt, t.attendantName, t.deskNumber, t.id);
                } else {
                    insertTicketStmt.run(t.id, t.displayId, t.serviceId, t.serviceName, t.priority, t.status, t.createdAt, t.calledAt, t.startedAt, t.finishedAt, t.attendantName, t.deskNumber);
                }
            }
        })();
        socket.broadcast.emit('sync-update', { type: 'TICKETS', data: data });
    });

    socket.on('update-services', (data) => {
        const items = Array.isArray(data) ? data : [data];
        const check = db.prepare("SELECT id FROM services WHERE id = ?");
        const upd = db.prepare("UPDATE services SET name=? WHERE id=?");
        const ins = db.prepare("INSERT INTO services (id, name, active) VALUES (?,?,?)");

        db.transaction(() => {
            for (const s of items) {
                if (check.get(s.id)) upd.run(s.name, s.id);
                else ins.run(s.id, s.name, 1);
            }
        })();
        socket.broadcast.emit('sync-update', { type: 'SERVICES', data: data });
    });

    socket.on('delete-service', (id) => {
        db.prepare("DELETE FROM services WHERE id = ?").run(id);
        socket.broadcast.emit('sync-delete-service', id);
    });

    socket.on('update-users', (data) => {
        const items = Array.isArray(data) ? data : [data];
        const check = db.prepare("SELECT id FROM users WHERE id = ?");
        const upd = db.prepare("UPDATE users SET name=?, username=?, password=?, deskNumber=?, serviceId=?, role=? WHERE id=?");
        const ins = db.prepare("INSERT INTO users (id, name, username, password, deskNumber, serviceId, role, active) VALUES (?,?,?,?,?,?,?,?)");

        db.transaction(() => {
            for (const u of items) {
                if (check.get(u.id)) upd.run(u.name, u.username, u.password, u.deskNumber, u.serviceId, u.role, u.id);
                else ins.run(u.id, u.name, u.username, u.password, u.deskNumber, u.serviceId, u.role, 1);
            }
        })();
        socket.broadcast.emit('sync-update', { type: 'USERS', data: data });
    });

    socket.on('delete-user', (id) => {
        db.prepare("DELETE FROM users WHERE id = ?").run(id);
        socket.broadcast.emit('sync-delete-user', id);
    });
});

