// --- 1. MOTOR DE BANCO DE DADOS JSON (CUSTOM LOWDB STYLE) ---
// Isso substitui o SQLite e não requer compilação. Funciona em qualquer Node.

let dbData = {
    users: [],
    services: [],
    tickets: [],
    config: {}
};

// Carrega o banco do disco
function loadDB() {
    try {
        if (fs.existsSync(DB_PATH)) {
            const fileContent = fs.readFileSync(DB_PATH, 'utf-8');
            dbData = JSON.parse(fileContent);
            // Garante estrutura mínima
            if (!Array.isArray(dbData.users)) dbData.users = [];
            if (!Array.isArray(dbData.services)) dbData.services = [];
            if (!Array.isArray(dbData.tickets)) dbData.tickets = [];
            if (!dbData.config) dbData.config = {};
            console.log('Banco de Dados JSON carregado com sucesso.');
        } else {
            console.log('Criando novo Banco de Dados JSON...');
            saveDB();
        }
    } catch (err) {
        console.error('Erro ao carregar DB JSON:', err);
    }
}

// Salva o banco no disco (Síncrono para garantir integridade em app local)
function saveDB() {
    try {
        fs.writeFileSync(DB_PATH, JSON.stringify(dbData, null, 2));
    } catch (err) {
        console.error('Erro ao salvar DB JSON:', err);
    }
}

