// --- SOCKET.IO ---

io.on('connection', (socket) => {
    // Envia dados iniciais
    socket.emit('initial-data', { 
        tickets: dbData.tickets.sort((a,b) => a.createdAt - b.createdAt), 
        services: dbData.services.filter(s => s.active), 
        users: dbData.users.filter(u => u.active) 
    });

    socket.on('update-tickets', (data) => {
        const items = Array.isArray(data) ? data : [data];
        for (const t of items) {
            const index = dbData.tickets.findIndex(x => x.id === t.id);
            if (index >= 0) {
                dbData.tickets[index] = { ...dbData.tickets[index], ...t };
            } else {
                dbData.tickets.push(t);
            }
        }
        saveDB();
        socket.broadcast.emit('sync-update', { type: 'TICKETS', data: data });
    });

    socket.on('update-services', (data) => {
        const items = Array.isArray(data) ? data : [data];
        for (const s of items) {
            const index = dbData.services.findIndex(x => x.id === s.id);
            if (index >= 0) {
                dbData.services[index] = { ...dbData.services[index], name: s.name, active: 1 };
            } else {
                dbData.services.push({ ...s, active: 1 });
            }
        }
        saveDB();
        socket.broadcast.emit('sync-update', { type: 'SERVICES', data: data });
    });

    socket.on('delete-service', (id) => {
        dbData.services = dbData.services.filter(s => s.id !== id);
        saveDB();
        socket.broadcast.emit('sync-delete-service', id);
    });

    socket.on('update-users', (data) => {
        const items = Array.isArray(data) ? data : [data];
        for (const u of items) {
            const index = dbData.users.findIndex(x => x.id === u.id);
            if (index >= 0) {
                dbData.users[index] = { ...dbData.users[index], ...u };
            } else {
                dbData.users.push({ ...u, active: 1 });
            }
        }
        saveDB();
        socket.broadcast.emit('sync-update', { type: 'USERS', data: data });
    });

    socket.on('delete-user', (id) => {
        dbData.users = dbData.users.filter(u => u.id !== id);
        saveDB();
        socket.broadcast.emit('sync-delete-user', id);
    });
});

