io.on('connection', (socket) => {
    // Initial Data Fetch
    const tickets = db.prepare("SELECT * FROM tickets ORDER BY createdAt ASC").all();
    const services = db.prepare("SELECT * FROM services WHERE active = 1").all();
    const users = db.prepare("SELECT * FROM users WHERE active = 1").all();

    socket.emit('initial-data', { 
        tickets, 
        services: services.map(s => ({...s, active: !!s.active})), 
        users: users.map(u => ({...u, active: !!u.active})) 
    });

    const upsertTicket = db.prepare(`
        INSERT INTO tickets (id, displayId, serviceId, serviceName, priority, status, createdAt, calledAt, startedAt, finishedAt, attendantName, deskNumber) 
        VALUES (@id, @displayId, @serviceId, @serviceName, @priority, @status, @createdAt, @calledAt, @startedAt, @finishedAt, @attendantName, @deskNumber)
        ON CONFLICT(id) DO UPDATE SET
        status=@status, calledAt=@calledAt, startedAt=@startedAt, finishedAt=@finishedAt, attendantName=@attendantName, deskNumber=@deskNumber
    `);

    socket.on('update-tickets', (data) => {
        const items = Array.isArray(data) ? data : [data];
        const updateTx = db.transaction((tickets) => {
            for (const t of tickets) upsertTicket.run(t);
        });
        updateTx(items);
        socket.broadcast.emit('sync-update', { type: 'TICKETS', data: data });
    });

    socket.on('update-services', (data) => {
        const items = Array.isArray(data) ? data : [data];
        const stmt = db.prepare("INSERT INTO services (id, name, active) VALUES (?, ?, ?) ON CONFLICT(id) DO UPDATE SET name=?, active=?");

        db.transaction(() => {
            for (const s of items) {
                stmt.run(s.id, s.name, 1, s.name, 1);
            }
        })();
        socket.broadcast.emit('sync-update', { type: 'SERVICES', data: data });
    });

    socket.on('delete-service', (id) => {
        db.prepare("DELETE FROM services WHERE id = ?").run(id);
        socket.broadcast.emit('sync-delete-service', id);
    });

    socket.on('update-users', (data) => {
        const items = Array.isArray(data) ? data : [data];
        const stmt = db.prepare(`
            INSERT INTO users (id, name, username, password, deskNumber, serviceId, role, active) 
            VALUES (@id, @name, @username, @password, @deskNumber, @serviceId, @role, 1)
            ON CONFLICT(id) DO UPDATE SET 
            name=@name, username=@username, password=@password, deskNumber=@deskNumber, serviceId=@serviceId, role=@role, active=1
        `);

        db.transaction(() => {
            for (const u of items) stmt.run(u);
        })();
        socket.broadcast.emit('sync-update', { type: 'USERS', data: data });
    });

    socket.on('delete-user', (id) => {
        db.prepare("DELETE FROM users WHERE id = ?").run(id);
        socket.broadcast.emit('sync-delete-user', id);
    });
});

