        if(data.clientEmail) setEmail(data.clientEmail);
        if(data.clientDocument) setDocument(data.clientDocument);
        if(data.clientPhone) setPhone(data.clientPhone);
        if(data.clientAddress) setAddress(data.clientAddress);
        if(data.clientCity) setCity(data.clientCity);
        if(data.clientLogo) setLogo(data.clientLogo);
      })
      .catch(err => console.error(err));
  }, []);

  const handleDocumentChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let val = e.target.value.replace(/\D/g, '');
    if (val.length > 14) val = val.slice(0, 14);
    if (val.length <= 11) {
       val = val.replace(/(\d{3})(\d)/, '$1.$2');
       val = val.replace(/(\d{3})(\d)/, '$1.$2');
       val = val.replace(/(\d{3})(\d{1,2})$/, '$1-$2');
    } else {
       val = val.replace(/^(\d{2})(\d)/, '$1.$2');
       val = val.replace(/^(\d{2})\.(\d{3})(\d)/, '$1.$2.$3');
       val = val.replace(/\.(\d{3})(\d)/, '.$1/$2');
       val = val.replace(/(\d{4})(\d)/, '$1-$2');
    }
    setDocument(val);
    setDocError('');
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let val = e.target.value.replace(/\D/g, '');
    if (val.length > 11) val = val.slice(0, 11);
    if (val.length > 2) val = `(${val.substring(0,2)}) ${val.substring(2)}`;
    if (val.length > 9) val = `${val.substring(0,9)}-${val.substring(9)}`;
    setPhone(val);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) { 
        alert("A imagem é muito grande. Tente usar uma menor que 2MB.");
        return; 
      }
      const reader = new FileReader();
      reader.onloadend = () => setLogo(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const validateDocs = () => {
    const cleanDoc = document.replace(/\D/g, '');
    if (cleanDoc.length === 11) {
      if (!isValidCPF(cleanDoc)) { setDocError('CPF Inválido'); return false; }
    } else if (cleanDoc.length === 14) {
      if (!isValidCNPJ(cleanDoc)) { setDocError('CNPJ Inválido'); return false; }
    } else {
      setDocError('Documento deve ter 11 (CPF) ou 14 (CNPJ) dígitos');
      return false;
    }
    return true;
  };

  const handleSaveClientInfo = async () => {
    if (!validateDocs()) return;
    try {
      const res = await fetch('/api/client-info', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          clientName: client, clientEmail: email, clientDocument: document,
          clientPhone: phone, clientAddress: address, clientCity: city, clientLogo: logo
        })
      });
      const data = await res.json();
      if (data.success) {
        setSaveMessage('Dados e Logo salvos com sucesso! Redirecionando...');
        if(onRefresh) onRefresh(); 
        setTimeout(() => { setSaveMessage(''); if(onNavigateHome) onNavigateHome(); }, 1500);
      } else {
        setSaveMessage('Erro ao salvar.');
      }
    } catch (e) { setSaveMessage('Erro de conexão.'); }
  };

  return (
    <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden shadow-lg animate-fade-in p-8">
        <h4 className="font-bold text-slate-700 dark:text-slate-200 mb-6 flex items-center gap-2 text-xl">
          <UserIcon size={24} className="text-indigo-600 dark:text-indigo-400" /> Cadastro da Empresa
        </h4>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="col-span-1">
              <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-3 uppercase">Logo da Empresa</label>
              <div className="border-2 border-dashed border-slate-300 dark:border-slate-600 rounded-xl p-4 flex flex-col items-center justify-center text-center h-64 relative">
                 {logo ? (
                   <>
                     <img src={logo} alt="Preview" className="max-h-48 max-w-full object-contain mb-2" />
                     <button onClick={() => setLogo('')} className="absolute top-2 right-2 bg-red-500 text-white p-1 rounded-full"><X size={16} /></button>
                   </>
                 ) : (
                   <div className="text-slate-400">
                     <ImageIcon size={48} className="mx-auto mb-2" />
                     <p className="text-sm">Clique para enviar a Logo</p>
                   </div>
                 )}
                 <input type="file" accept="image/*" onChange={handleLogoUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
              </div>
            </div>
            <div className="col-span-2 space-y-4">
               <div>
                 <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">Nome / Empresa</label>
                 <input value={client} onChange={e => setClient(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded p-3 outline-none text-slate-900 dark:text-white" />
               </div>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <div>
                   <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">Endereço</label>
                   <input value={address} onChange={e => setAddress(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded p-3 outline-none text-slate-900 dark:text-white" />
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">Cidade</label>
                   <input value={city} onChange={e => setCity(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded p-3 outline-none text-slate-900 dark:text-white" />
                 </div>
               </div>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <div>
                   <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">E-mail</label>
                   <input value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded p-3 outline-none text-slate-900 dark:text-white" type="email" />
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">Telefone</label>
                   <input value={phone} onChange={handlePhoneChange} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded p-3 outline-none text-slate-900 dark:text-white" />
                 </div>
               </div>
               <div>
                 <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">CPF / CNPJ</label>
                 <input value={document} onChange={handleDocumentChange} className={`w-full bg-slate-50 dark:bg-slate-900 border ${docError ? 'border-red-500' : 'border-slate-300 dark:border-slate-600'} rounded p-3 outline-none text-slate-900 dark:text-white`} maxLength={18} />
                 {docError && <p className="text-xs text-red-500 mt-1">{docError}</p>}
               </div>
               <div className="pt-4 flex items-center gap-4">
                  <button onClick={handleSaveClientInfo} className="bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-3 px-8 rounded-lg shadow flex items-center gap-2"><Save size={18} /> Salvar Cadastro</button>
                  {saveMessage && <p className="text-sm text-emerald-600 font-bold animate-pulse">{saveMessage}</p>}
               </div>
            </div>
        </div>
    </div>
  );
};

const LicenseTab = () => {
  const [key, setKey] = useState('');
  const [status, setStatus] = useState<any>(null);
  const [message, setMessage] = useState('');

  React.useEffect(() => {
    fetch('/api/license')
      .then(async res => {
         if (!res.ok) return {};
         const text = await res.text();
         try { return JSON.parse(text); } catch { return {}; }
      })
      .then(data => setStatus(data))
      .catch(console.error);
  }, []);

  const handleActivate = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await fetch('/api/license', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ key }) });
      const data = await res.json();
      if (data.success) {
        setMessage('Sistema ativado com sucesso!');
        // Reload status to get dates
        const statusRes = await fetch('/api/license');
        const statusData = await statusRes.json();
        setStatus(statusData);
        setKey(''); // Clear input on success
      } else { setMessage('Erro: ' + data.message); }
    } catch (error) { setMessage('Erro de conexão.'); }
  };

  return (
    <div className="animate-fade-in">
      <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-4 flex items-center gap-2"><Lock size={24} /> Licenciamento</h3>

      {/* STATUS BLOCK */}
      {status && (
          <div className="mb-8 p-4 bg-slate-50 dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-700">
             <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-xs text-slate-500 uppercase font-bold">Status</p>
                  <p className={`text-lg font-bold ${status.hasLicense ? 'text-emerald-600' : 'text-yellow-600'}`}>{status.hasLicense ? 'Ativado' : 'Versão Trial'}</p>
                </div>

                {status.hasLicense && status.licenseExpiryDate && (
                  <>
                    <div>
                       <p className="text-xs text-slate-500 uppercase font-bold flex items-center gap-1"><Calendar size={12}/> Vencimento</p>
                       <p className="text-lg font-bold text-slate-700 dark:text-slate-200">
                         {new Date(status.licenseExpiryDate).toLocaleDateString('pt-BR')}
                       </p>
                    </div>
                    <div className="col-span-2 border-t border-slate-200 dark:border-slate-700 pt-2 mt-2">
                       <p className="text-xs text-slate-500 uppercase font-bold flex items-center gap-1"><Clock size={12}/> Tempo Restante</p>
                       <p className="text-sm font-bold text-indigo-600 dark:text-indigo-400">
                         {status.trialDaysLeft} dias restantes
                       </p>
                    </div>
                  </>
                )}

                {!status.hasLicense && (
                  <div>
                    <p className="text-xs text-slate-500 uppercase font-bold">Dias</p>
                    <p className="text-lg font-bold text-orange-500">{status.trialDaysLeft} dias de teste</p>
                  </div>
                )}
             </div>
          </div>
      )}

      {/* INPUT FORM (ALWAYS VISIBLE NOW) */}
      <div className="mt-6">
        {status?.hasLicense && (
            <div className="mb-4 pt-4 border-t border-slate-200 dark:border-slate-700">
                <h4 className="text-sm font-bold text-slate-700 dark:text-slate-300 mb-1">Atualizar Licença</h4>
                <p className="text-xs text-slate-500">Deseja renovar ou trocar sua licença? Insira a nova chave abaixo.</p>
            </div>
        )}
        <form onSubmit={handleActivate} className="flex gap-2">
           <input required value={key} onChange={e => setKey(e.target.value)} placeholder={status?.hasLicense ? "Nova Chave de Licença" : "Chave de Ativação"} className="flex-1 bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded p-3 outline-none text-slate-900 dark:text-white font-mono uppercase" />
           <button type="submit" className="bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 px-6 rounded-lg shadow-lg">
              {status?.hasLicense ? 'Atualizar' : 'Ativar'}
           </button>
        </form>
        {message && <p className="mt-2 text-sm font-bold text-emerald-500">{message}</p>}
      </div>
    </div>
  );
};

