  const handleRestoreBackup = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && confirm("ATENÇÃO: Isso sobrescreverá TODOS os dados. Continuar?")) {
      const reader = new FileReader();
      reader.onload = async (ev) => {
         try {
           const json = JSON.parse(ev.target?.result as string);
           const res = await fetch('/api/restore', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ data: json }) });
           const result = await res.json();
           if (result.success) { setRestoreMessage('Restaurado!'); setTimeout(() => window.location.reload(), 1500); } 
           else { setRestoreMessage('Erro: ' + result.message); }
