app.post('/api/restore', async (req, res) => {
    const { data } = req.body;
    if (!data) return res.status(400).json({ success: false });

    try {
        await db.run("BEGIN TRANSACTION");
        await db.run("DELETE FROM tickets");
        await db.run("DELETE FROM services");
        await db.run("DELETE FROM users");

        if (data.services) {
            for (const s of data.services) {
                await db.run("INSERT INTO services (id, name, active) VALUES (?,?,?)", [s.id, s.name, s.active ? 1 : 0]);
            }
        }
        if (data.users) {
            for (const u of data.users) {
                await db.run("INSERT INTO users (id, name, username, password, deskNumber, serviceId, role, active) VALUES (?,?,?,?,?,?,?,?)", [u.id, u.name, u.username, u.password, u.deskNumber, u.serviceId, u.role, u.active ? 1 : 0]);
            }
        }
        if (data.tickets) {
            for (const t of data.tickets) {
                await db.run("INSERT INTO tickets (id, displayId, serviceId, serviceName, priority, status, createdAt, calledAt, startedAt, finishedAt, attendantName, deskNumber) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)", 
                [t.id, t.displayId, t.serviceId, t.serviceName, t.priority, t.status, t.createdAt, t.calledAt, t.startedAt, t.finishedAt, t.attendantName, t.deskNumber]);
            }
        }

        await db.run("COMMIT");
        io.emit('sync-update', { type: 'RESET' });
        res.json({ success: true });
    } catch (e) {
        await db.run("ROLLBACK");
        console.error(e);
        res.status(500).json({ success: false });
    }
});

