const LayoutTab = () => {
  const [template, setTemplate] = useState('');
  const [msg, setMsg] = useState('');
  const DEFAULT_TEMPLATE = `<html><head><style>@page { margin: 0; } body { margin: 0; padding: 5px; font-family: 'Arial', sans-serif; text-align: center; color: black; } .logo { max-width: 80%; max-height: 60px; margin-bottom: 5px; } h2 { font-size: 14px; margin: 2px 0; text-transform: uppercase; } .divider { border-top: 1px dashed black; margin: 5px 0; width: 100%; } .label { font-size: 12px; font-weight: bold; margin-top: 5px; } .password { font-size: {{FONT_SIZE_PX}}px; font-weight: 900; margin: 5px 0; line-height: 1; } .info { font-size: 16px; font-weight: bold; margin: 2px 0; } .meta { font-size: 10px; margin-top: 10px; }</style></head><body>{{LOGO}}<h2>{{EMPRESA}}</h2><div class="divider"></div><div class="label">SENHA</div><div class="password">{{SENHA}}</div><div class="info">{{SERVICO}}</div><div class="info">{{PRIORIDADE}}</div><div class="divider"></div><div class="meta">{{DATA}} - {{HORA}}</div><br/><br/></body></html>`;

  useEffect(() => {
    fetch('/api/printer-config')
      .then(async res => {
         const text = await res.text();
         try { return JSON.parse(text); } catch { return {}; }
      })
      .then(data => setTemplate(data.ticketTemplate || DEFAULT_TEMPLATE));
  }, []);

  const handleSave = async () => {
    try {
       const currentRes = await fetch('/api/printer-config');
       const currentConfig = await currentRes.json();
       await fetch('/api/printer-config', {
         method: 'POST',
         headers: { 'Content-Type': 'application/json' },
         body: JSON.stringify({ ...currentConfig, ticketTemplate: template })
       });
       setMsg('Salvo!');
       setTimeout(() => setMsg(''), 2000);
    } catch(e) { setMsg('Erro'); }
  };

  return (
    <div className="animate-fade-in p-2">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 h-[400px]">
         <div className="flex flex-col h-full">
            <label className="text-xs font-bold text-slate-500 mb-1">HTML do Ticket</label>
            <textarea 
              value={template}
              onChange={e => setTemplate(e.target.value)}
