                         <p className="text-blue-600 dark:text-blue-400 text-xs mb-3 leading-relaxed">
                             Salva todas as senhas, serviços, usuários e configurações em um arquivo JSON seguro.
                         </p>
                         <button onClick={() => window.open('/api/backup', '_blank')} className="bg-blue-600 hover:bg-blue-500 text-white py-1.5 px-4 rounded text-xs font-bold flex items-center gap-2 transition-colors">
