          </div>
        </div>

        {/* Filter Section - Hidden on Print */}
        <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm mb-6 animate-fade-in no-print">
          <div className="flex items-center gap-2 mb-4 text-slate-700 dark:text-slate-300 font-bold border-b border-slate-200 dark:border-slate-700 pb-2">
